import { useState, useEffect } from "react";
import "./App.css";

function App() {
  const [tarefa, setTarefa] = useState("");
  const [prioridade, setPrioridade] = useState("media");
  const [editandoIndex, setEditandoIndex] = useState(null);
  const [textoEditado, setTextoEditado] = useState("");
  const [filtro, setFiltro] = useState("todas");

  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (!tarefa.trim()) return;
    setLista([...lista, { texto: tarefa, concluida: false, prioridade }]);
    setTarefa("");
    setPrioridade("media");
  }

  function removerTarefa(index) {
    setLista(lista.filter((_, i) => i !== index));
  }

  function toggleTarefa(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, concluida: !item.concluida } : item
      )
    );
  }

  function iniciarEdicao(index) {
    setEditandoIndex(index);
    setTextoEditado(lista[index].texto);
    setPrioridade(lista[index].prioridade);
  }

  function salvarEdicao(index) {
    setLista(
      lista.map((item, i) =>
        i === index ? { ...item, texto: textoEditado, prioridade } : item
      )
    );
    setEditandoIndex(null);
    setTextoEditado("");
    setPrioridade("media");
  }

  const listaFiltrada = lista.filter((item) => {
    if (filtro === "concluidas") return item.concluida;
    if (filtro === "pendentes") return !item.concluida;
    return true;
  });

  const coresPrioridade = {
    baixa: "low",
    media: "medium",
    alta: "high",
  };

  const total = lista.length;
  const concluidas = lista.filter((t) => t.concluida).length;
  const pendentes = total - concluidas;

  return (
    <div className="page">
      <div className="container">

        <h1 className="title">📝 To-Do List</h1>

        {/* CONTADORES */}
        <div className="contadores">
          <div className="badge total">Total {total}</div>
          <div className="badge done">Concluídas {concluidas}</div>
          <div className="badge pending">Pendentes {pendentes}</div>
        </div>

        {/* INPUT */}
        <div className="input-area">
          <input
            value={tarefa}
            onChange={(e) => setTarefa(e.target.value)}
            placeholder="Digite uma tarefa..."
            className="input"
          />

          <select
            value={prioridade}
            onChange={(e) => setPrioridade(e.target.value)}
            className="select"
          >
            <option value="baixa">Baixa</option>
            <option value="media">Média</option>
            <option value="alta">Alta</option>
          </select>

          <button className="add-btn" onClick={adicionarTarefa}>
            +
          </button>
        </div>

        {/* FILTROS */}
        <div className="filters">
          <button onClick={() => setFiltro("todas")}>Todas</button>
          <button onClick={() => setFiltro("concluidas")}>Concluídas</button>
          <button onClick={() => setFiltro("pendentes")}>Pendentes</button>
        </div>

        {/* LISTA */}
        <ul className="list">
          {listaFiltrada.map((item, index) => (
            <li
              key={index}
              className={`item ${item.concluida ? "done" : ""} ${item.prioridade}`}
            >
              {editandoIndex === index ? (
                <input
                  value={textoEditado}
                  onChange={(e) => setTextoEditado(e.target.value)}
                  className="input edit"
                />
              ) : (
                <span>{item.texto}</span>
              )}

              <div className="actions">
                <button onClick={() => toggleTarefa(index)}>✔</button>

                {editandoIndex === index ? (
                  <button onClick={() => salvarEdicao(index)}>💾</button>
                ) : (
                  <button onClick={() => iniciarEdicao(index)}>✏️</button>
                )}

                <button onClick={() => removerTarefa(index)}>✖</button>
              </div>
            </li>
          ))}
        </ul>

      </div>
    </div>
  );
}

export default App;
